const inputData = $input.all();

// Parse all API responses
const jobs = Array.isArray(inputData[0].json) ? inputData[0].json : (inputData[0].json.jobs || inputData[0].json.data || []);
const workers = Array.isArray(inputData[1].json) ? inputData[1].json : (inputData[1].json.workers || inputData[1].json.data || []);
const invoices = Array.isArray(inputData[2].json) ? inputData[2].json : (inputData[2].json.invoices || inputData[2].json.data || []);
const inventory = Array.isArray(inputData[3].json) ? inputData[3].json : (inputData[3].json.items || inputData[3].json.data || []);

// Analyze jobs
const todayJobs = jobs.filter(j => {
  const jobDate = j.scheduled_date || j.date;
  if (!jobDate) return true;
  const today = new Date().toISOString().split('T')[0];
  return jobDate === today;
});

const pendingJobs = todayJobs.filter(j => j.status === 'pending' || j.status === 'assigned');
const inProgressJobs = todayJobs.filter(j => j.status === 'in_progress');
const completedJobs = todayJobs.filter(j => j.status === 'completed');

// Worker stats
const availableWorkers = workers.filter(w => (w.current_jobs || 0) < (w.max_jobs || 5));
const busyWorkers = workers.filter(w => (w.current_jobs || 0) >= (w.max_jobs || 5));

// Invoice stats
const totalPendingAmount = invoices.reduce((s, i) => s + (i.total_amount || i.amount || 0), 0);

// Inventory stats
const criticalItems = inventory.filter(i => i.quantity <= (i.min_stock || 0) * 0.3);

// Build the digest message
const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

let message = `☀️ *Kosai Daily Operations Digest*\n📅 ${dateStr}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━\n*📋 JOBS TODAY*\n━━━━━━━━━━━━━━━━━━━\n`;
message += `📌 Total: ${todayJobs.length}\n`;
message += `⏳ Pending: ${pendingJobs.length}\n`;
message += `🛠️ In Progress: ${inProgressJobs.length}\n`;
message += `✅ Completed: ${completedJobs.length}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━\n*👷 WORKERS*\n━━━━━━━━━━━━━━━━━━━\n`;
message += `🟢 Available: ${availableWorkers.length}\n`;
message += `🔴 Fully Booked: ${busyWorkers.length}\n`;
message += `👥 Total Active: ${workers.length}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━\n*💰 FINANCIALS*\n━━━━━━━━━━━━━━━━━━━\n`;
message += `🧾 Pending Invoices: ${invoices.length}\n`;
message += `💵 Total Outstanding: $${totalPendingAmount.toFixed(2)}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━\n*📦 INVENTORY*\n━━━━━━━━━━━━━━━━━━━\n`;
message += `🟡 Low Stock Items: ${inventory.length}\n`;
if (criticalItems.length > 0) {
  message += `🔴 *CRITICAL:* ${criticalItems.map(i => i.name).join(', ')}\n`;
}
message += `\n`;

message += `━━━━━━━━━━━━━━━━━━━\n`;
message += `📊 *Summary:* ${pendingJobs.length} jobs pending, ${availableWorkers.length} workers available, $${totalPendingAmount.toFixed(2)} outstanding\n\n`;
message += `💡 *Tip:* Check the Kosai portal for detailed reports.`;

return {
  digest: message,
  stats: {
    totalJobs: todayJobs.length,
    pendingJobs: pendingJobs.length,
    inProgressJobs: inProgressJobs.length,
    completedJobs: completedJobs.length,
    availableWorkers: availableWorkers.length,
    busyWorkers: busyWorkers.length,
    totalWorkers: workers.length,
    pendingInvoices: invoices.length,
    totalOutstanding: totalPendingAmount,
    lowStockItems: inventory.length,
    criticalItems: criticalItems.length
  }
};
